var acc = makeAccumulator();
assert(acc(10) === 10, 'first call returns 10');
assert(acc(5) === 15, 'then 15');
assert(acc(-3) === 12, 'then 12');

var a = makeAccumulator(), b = makeAccumulator();
a(100);
assert(b(1) === 1, 'b has its own total, untouched by a');

var sw = toggle('ON', 'OFF');
assert(sw() === 'ON', '1st is a');
assert(sw() === 'OFF', '2nd is b');
assert(sw() === 'ON', '3rd is a again');
assert(sw() === 'OFF', '4th is b again');

var x = toggle('a', 'b'), y = toggle('a', 'b');
x();
assert(y() === 'a', 'y still starts on a even after x advanced');

var gate = limiter(2);
assert(gate() === true, '1st pass');
assert(gate() === true, '2nd pass');
assert(gate() === false, '3rd denied');
assert(gate() === false, '4th denied');

var g1 = limiter(1), g2 = limiter(1);
g1();
assert(g2() === true, 'g2 still has its own pass left');

var boot = once(function (x) { return x * 2; });
assert(boot(5) === 10, 'first call computes');
assert(boot(9) === 10, 'later calls reuse the first result');
assert(boot(100) === 10, 'still the first result');

var runs = 0;
var f = once(function () { runs += 1; return 'done'; });
f(); f(); f();
assert(runs === 1, 'the wrapped fn must execute exactly once');

var f = once(function () { return { id: 7 }; });
assertEqual(f(), { id: 7 });
assertEqual(f(), { id: 7 });

var inc = function (x) { return x + 1; };
assert(applyN(inc, 3)(0) === 3, 'inc applied 3 times to 0 is 3');
assert(applyN(inc, 5)(10) === 15, 'inc applied 5 times to 10 is 15');

var inc = function (x) { return x + 1; };
var plus2 = applyN(inc, 2);
assert(plus2(0) === 2 && plus2(40) === 42, 'the returned function can be called many times');
